data.query:
query ConnectorDetails($connectorWhere: ConnectorWhereInput, $connectionWhere: ConnectionWhereInput) {
  connector(where: $connectorWhere, first: 1) {
    edges {
      node {
        id
        name
        description
        optionsSchema
        credentialsSchema
        _metadata {
          installedPackageId
          packageInstallationId
          packageDefinitionId
          packageDefinitionVersionId
        }
        createdAt
        createdByUserId
        createdByUser {
          id
          email
          firstName
          lastName
          active
        }
        updatedAt
        updatedByUserId
        updatedByUser {
          id
          email
          firstName
          lastName
          active
        }
      }
    }
  }
  connection(where: $connectionWhere, first: 1) {
    edges {
      node {
        id
        name
        active
        connectorId
        connector {
          id
          name
          description
          optionsSchema
          credentialsSchema
        }
        url
        options
        credentials
        requestPayloadLogging
        responsePayloadLogging
        _metadata {
          installedPackageId
          packageInstallationId
          packageDefinitionId
          packageDefinitionVersionId
        }
        createdAt
        createdByUserId
        createdByUser {
          id
          email
          firstName
          lastName
          active
        }
        updatedAt
        updatedByUserId
        updatedByUser {
          id
          email
          firstName
          lastName
          active
        }
      }
    }
  }
}

data.variablesTransform:
{
  "connectorWhere": {
    "id": { "_eq": id }
  },
  "connectionWhere": {
    "id": { "_eq": id }
  }
}

data.transform:
(
  $inputId := $state.payload.id;
  $connectorData := connector.edges[0].node;
  $connectionData := connection.edges[0].node;

  /* Return connector details if found */
  $connectorData ? {
    "type": "connector",
    "connector": {
      "id": $connectorData.id,
      "name": $connectorData.name,
      "description": $connectorData.description
    },
    "schemas": {
      "optionsSchema": $connectorData.optionsSchema,
      "credentialsSchema": $connectorData.credentialsSchema
    },
    "metadata": $connectorData._metadata,
    "audit": {
      "createdAt": $connectorData.createdAt,
      "createdBy": $connectorData.createdByUser ? $connectorData.createdByUser.firstName & " " & $connectorData.createdByUser.lastName : null,
      "updatedAt": $connectorData.updatedAt,
      "updatedBy": $connectorData.updatedByUser ? $connectorData.updatedByUser.firstName & " " & $connectorData.updatedByUser.lastName : null
    },
    "summary": {
      "hasOptionsSchema": $connectorData.optionsSchema != null,
      "hasCredentialsSchema": $connectorData.credentialsSchema != null
    }
  } :
  /* Return connection details if found */
  $connectionData ? {
    "type": "connection",
    "connection": {
      "id": $connectionData.id,
      "name": $connectionData.name,
      "active": $connectionData.active,
      "url": $connectionData.url,
      "requestPayloadLogging": $connectionData.requestPayloadLogging,
      "responsePayloadLogging": $connectionData.responsePayloadLogging
    },
    "connector": {
      "id": $connectionData.connector.id,
      "name": $connectionData.connector.name,
      "description": $connectionData.connector.description
    },
    "configuration": {
      "options": $connectionData.options,
      "credentials": "[REDACTED]"
    },
    "schemas": {
      "optionsSchema": $connectionData.connector.optionsSchema,
      "credentialsSchema": $connectionData.connector.credentialsSchema
    },
    "metadata": $connectionData._metadata,
    "audit": {
      "createdAt": $connectionData.createdAt,
      "createdBy": $connectionData.createdByUser ? $connectionData.createdByUser.firstName & " " & $connectionData.createdByUser.lastName : null,
      "updatedAt": $connectionData.updatedAt,
      "updatedBy": $connectionData.updatedByUser ? $connectionData.updatedByUser.firstName & " " & $connectionData.updatedByUser.lastName : null
    }
  } :
  /* Not found */
  {
    "error": "Not found",
    "message": "No connector or connection found with ID: " & $inputId,
    "searchedId": $inputId
  }
)

