data.query:
query ConnectorToGraph($connectorWhere: ConnectorWhereInput, $connectionWhere: ConnectionWhereInput, $first: Int) {
  connector(where: $connectorWhere, first: $first) {
    total
    edges {
      node {
        id
        name
        description
        optionsSchema
        credentialsSchema
      }
    }
  }
  connection(where: $connectionWhere, first: $first) {
    total
    edges {
      node {
        id
        name
        active
        connectorId
        connector {
          id
          name
          description
        }
        url
        requestPayloadLogging
        responsePayloadLogging
      }
    }
  }
}

data.variablesTransform:
{
  "connectorWhere": {
    "name": $isNilOrEmpty(name) ? undefined : {
      "_contains": name
    }
  },
  "connectionWhere": {
    "name": $isNilOrEmpty(name) ? undefined : {
      "_contains": name
    },
    "active": activeOnly = false ? undefined : {
      "_eq": true
    }
  },
  "first": $isNilOrEmpty(first) ? 100 : first
}

data.transform:
(
  $connectors := connector.edges.node;
  $connections := connection.edges.node;

  /* Build unified graph output */
  {
    "connectors": [$connectors.{
      "id": id,
      "name": name,
      "description": description,
      "hasOptionsSchema": optionsSchema != null,
      "hasCredentialsSchema": credentialsSchema != null
    }],
    "connections": [$connections.{
      "id": id,
      "name": name,
      "active": active,
      "connectorId": connectorId,
      "connectorName": connector.name,
      "url": url,
      "requestPayloadLogging": requestPayloadLogging,
      "responsePayloadLogging": responsePayloadLogging
    }],
    "graph": {
      "nodes": [
        $connectors.{
          "id": id,
          "type": "connector",
          "label": name,
          "description": description
        },
        $connections.{
          "id": id,
          "type": "connection",
          "label": name,
          "active": active,
          "url": url
        }
      ],
      "edges": [
        $connections.{
          "source": id,
          "target": connectorId,
          "type": "uses_connector",
          "label": "uses"
        }
      ]
    },
    "summary": {
      "totalConnectors": connector.total,
      "returnedConnectors": $count($connectors),
      "totalConnections": connection.total,
      "returnedConnections": $count($connections),
      "activeConnections": $count($connections[active = true]),
      "inactiveConnections": $count($connections[active = false]),
      "connectorsInUse": $distinct($connections.connectorId),
      "unusedConnectors": $filter($connectors, function($c) { $not($c.id in $connections.connectorId) }).id
    },
    "hint": "Use connector_details with a connector or connection ID to get full configuration details."
  }
)

