data.transform:
(
  $flows := dataFlow.edges.node;

  /* Build graph-friendly output */
  {
    "dataFlows": [$flows.{
      "id": id,
      "name": name,
      "description": description,
      "active": active,
      "dataFlowTypeId": dataFlowTypeId,
      "logLevelId": logLevelId,
      "module": {
        "id": module.id,
        "name": module.name,
        "description": module.description,
        "system": module.system
      },
      "relationships": {
        "substitutesDataFlowId": substitutesDataFlowId,
        "substitutesDataFlowName": substitutesDataFlow.name,
        "moduleId": moduleId
      },
      "deployment": {
        "currentDeploymentId": currentDeploymentId,
        "effectiveDeploymentId": effectiveDeploymentId,
        "isDeployed": currentDeploymentId != null,
        "hasEffectiveDeployment": effectiveDeploymentId != null
      }
    }],
    "graph": {
      "nodes": [
        $flows.{
          "id": id,
          "type": "dataFlow",
          "label": name,
          "module": module.name,
          "flowType": dataFlowTypeId
        },
        $distinct($flows.module).{
          "id": id,
          "type": "module",
          "label": name,
          "system": system
        }
      ],
      "edges": [
        $flows.{
          "source": id,
          "target": moduleId,
          "type": "belongs_to_module"
        },
        $flows[substitutesDataFlowId != null].{
          "source": id,
          "target": substitutesDataFlowId,
          "type": "substitutes"
        }
      ]
    },
    "summary": {
      "totalFlows": dataFlow.total,
      "returnedFlows": $count($flows),
      "modules": $distinct($flows.module.name),
      "moduleCount": $count($distinct($flows.module.id)),
      "flowTypes": $distinct($flows.dataFlowTypeId),
      "deployedCount": $count($flows[currentDeploymentId != null]),
      "substitutionCount": $count($flows[substitutesDataFlowId != null])
    },
    "hint": "Use dataflow_details to get full node and connection details for a specific flow."
  }
)

