query ScreenDetails($where: ScreenWhereInput) {
  screen(where: $where, first: 1) {
    edges {
      node {
        id
        name
        description
        active
        edgeScreen
        forceFullscreen
        moduleId
        module {
          id
          name
          description
          system
          moduleGroupId
        }
        routes {
          edges {
            node {
              id
              title
              path
              moduleId
              screenId
              isMenuAccessible
              submenu
              isFullscreen
            }
          }
        }
        versions {
          edges {
            node {
              id
              number
              description
              screenId
              deployed
            }
          }
        }
        deployments {
          edges {
            node {
              id
              screenId
              screenVersionId
            }
          }
        }
        currentDeploymentId
        currentDeployment {
          id
          screenId
          screenVersionId
        }
        substitutesScreenId
        substitutesScreen {
          id
          name
          description
          active
        }
        substitutedByScreen {
          id
          name
          description
          active
        }
        effectiveDeploymentId
        effectiveDeployment {
          id
          screenId
          screenVersionId
        }
        isWidget
        elements {
          edges {
            node {
              id
              elementId
              name
              type
              description
              path
              screenId
              componentName
              label
              dataPath
            }
          }
        }
      }
    }
  }
}

