data.transform:
(
  $screens := screen.edges.node;

  /* Get route paths for each screen */
  $getRoutes := function($routes) {
    $routes.edges.node.{
      "id": id,
      "path": path,
      "title": title,
      "menuAccessible": isMenuAccessible,
      "submenu": submenu,
      "isFullscreen": isFullscreen
    }
  };

  /* Build graph-friendly output */
  {
    "screens": [$screens.{
      "id": id,
      "name": name,
      "description": description,
      "active": active,
      "isWidget": isWidget,
      "edgeScreen": edgeScreen,
      "forceFullscreen": forceFullscreen,
      "module": {
        "id": module.id,
        "name": module.name,
        "description": module.description,
        "system": module.system
      },
      "routes": $getRoutes(routes),
      "routeCount": $count(routes.edges),
      "primaryRoute": routes.edges[0].node.path,
      "menuPaths": [routes.edges.node[isMenuAccessible = true].path],
      "relationships": {
        "substitutesScreenId": substitutesScreenId,
        "substitutesScreenName": substitutesScreen.name,
        "moduleId": moduleId
      },
      "deployment": {
        "currentDeploymentId": currentDeploymentId,
        "effectiveDeploymentId": effectiveDeploymentId,
        "isDeployed": currentDeploymentId != null,
        "hasEffectiveDeployment": effectiveDeploymentId != null
      }
    }],
    "graph": {
      "nodes": [
        $screens.{
          "id": id,
          "type": "screen",
          "label": name,
          "module": module.name,
          "isWidget": isWidget
        },
        $distinct($screens.module).{
          "id": id,
          "type": "module",
          "label": name,
          "system": system
        }
      ],
      "edges": [
        $screens.{
          "source": id,
          "target": moduleId,
          "type": "belongs_to_module"
        },
        $screens[substitutesScreenId != null].{
          "source": id,
          "target": substitutesScreenId,
          "type": "substitutes"
        }
      ]
    },
    "summary": {
      "totalScreens": screen.total,
      "returnedScreens": $count($screens),
      "modules": $distinct($screens.module.name),
      "moduleCount": $count($distinct($screens.module.id)),
      "widgetCount": $count($screens[isWidget = true]),
      "edgeScreenCount": $count($screens[edgeScreen = true]),
      "deployedCount": $count($screens[currentDeploymentId != null]),
      "substitutionCount": $count($screens[substitutesScreenId != null]),
      "totalRoutes": $sum($screens.($count(routes.edges)))
    },
    "hint": "Use screen_details to get full element and version details for a specific screen."
  }
)

